import React, { useEffect, useState } from 'react';

function StructuredSuiteConfig({ apiBase, isRunning, isInitialized, onRunStructuredSuite }) {
  const [suite, setSuite] = useState({
    suite_name: '',
    count: 0,
    errors: [],
    plan_summary: {},
    preview: []
  });

  const [safeSubset, setSafeSubset] = useState({ count: 0, preview: [] });
  const [recommended, setRecommended] = useState({ count: 0, preview: [] });
  const [busy, setBusy] = useState(false);

  const refresh = async () => {
    try {
      const res1 = await fetch(`${apiBase}/api/structured-suite`);
      const data1 = await res1.json();
      setSuite(data1);

      const res2 = await fetch(`${apiBase}/api/structured-suite/safe-subset`);
      const data2 = await res2.json();
      setSafeSubset(data2);

      const res3 = await fetch(`${apiBase}/api/structured-suite/recommended-first-run`);
      const data3 = await res3.json();
      setRecommended(data3);
    } catch (err) {
      console.error('Structured suite refresh failed:', err);
    }
  };

  useEffect(() => { refresh(); }, []);

  const onPick = async (e) => {
    const f = (e.target.files || [])[0];
    if (!f) return;

    setBusy(true);
    try {
      const fd = new FormData();
      fd.append('file', f);
      const res = await fetch(`${apiBase}/api/structured-suite/upload`, { method: 'POST', body: fd });
      await res.json();
      await refresh();
    } finally {
      setBusy(false);
      e.target.value = '';
    }
  };

  return (
    <div style={{ marginTop: '14px' }}>
      <h3 style={{ fontSize: '14px', fontWeight: 700, marginBottom: '10px', color: '#667eea' }}>
        Structured Scenario Workbook
      </h3>

      <input
        type="file"
        disabled={busy || isRunning}
        onChange={onPick}
        style={{ width: '100%', marginBottom: '10px' }}
        accept=".xlsx"
      />

      <div style={{ fontSize: '12px', color: '#a0aec0', marginBottom: '6px' }}>
        Loaded: {suite.count || 0} structured scenarios {suite.suite_name ? `(${suite.suite_name})` : ''}
      </div>

      {suite.errors && suite.errors.length > 0 && (
        <div style={{ background: '#742a2a', color: '#fed7d7', padding: '8px', borderRadius: '6px', fontSize: '12px', marginBottom: '10px' }}>
          {suite.errors.map((er, i) => <div key={i}>• {er}</div>)}
        </div>
      )}

      {suite.plan_summary && suite.plan_summary.total > 0 && (
        <div style={{ background: '#1a202c', padding: '10px', borderRadius: '8px', marginBottom: '10px', fontSize: '12px' }}>
          <div><strong>Total:</strong> {suite.plan_summary.total}</div>
          <div><strong>Full:</strong> {suite.plan_summary.full} | <strong>Partial:</strong> {suite.plan_summary.partial} | <strong>Manual:</strong> {suite.plan_summary.manual}</div>
        </div>
      )}

      <div style={{ background: '#1a202c', padding: '10px', borderRadius: '8px', marginBottom: '10px' }}>
        <div style={{ fontSize: '12px', fontWeight: 700, color: '#68d391', marginBottom: '6px' }}>
          Safe Subset: {safeSubset.count || 0}
        </div>
        {(safeSubset.preview || []).slice(0, 5).map((s, i) => (
          <div key={i} style={{ fontSize: '11px', color: '#cbd5e0', marginBottom: '4px' }}>
            • {s.id} — {s.execution_mode}
          </div>
        ))}
      </div>

      <div style={{ background: '#1a202c', padding: '10px', borderRadius: '8px', marginBottom: '10px' }}>
        <div style={{ fontSize: '12px', fontWeight: 700, color: '#63b3ed', marginBottom: '6px' }}>
          Recommended First Run
        </div>
        {(recommended.preview || []).slice(0, 5).map((s, i) => (
          <div key={i} style={{ fontSize: '11px', color: '#cbd5e0', marginBottom: '4px' }}>
            • {s.id} — {s.family} — {s.execution_mode}
          </div>
        ))}
      </div>

      <button
        className="btn btn-primary"
        disabled={!isInitialized || isRunning || busy || !(suite.count > 0)}
        onClick={onRunStructuredSuite}
        style={{ width: '100%' }}
      >
        Run Structured Suite
      </button>

      <button
        className="btn btn-sm"
        style={{ width: '100%', marginTop: '8px', background: '#2d3748', color: '#a0aec0' }}
        onClick={refresh}
        disabled={busy || isRunning}
      >
        Refresh Structured Suite
      </button>
    </div>
  );
}

export default StructuredSuiteConfig;
